// Created: 2026-05-22

/**
 * Worktree Exit Finalizer — WorktreeRemove hook (M168 Phase 4, #1914)
 *
 * When CC removes a worktree, mark every `worktree_links` row whose child
 * session lived in that worktree as `result_status = 'completed'`, then
 * delete the corresponding advisory file under the parent's
 * `<parentDir>/.claude/state/children/<child_sid>.json`.
 *
 * Child sessions are identified by joining `sessions.worktree_path` →
 * `worktree_links.child_sid`, so we don't need to know the child sid up
 * front (CC's WorktreeRemove event only delivers `worktree_path`).
 *
 * An event entry is appended to `<projectDir>/.claude/logs/worktree-events.jsonl`
 * via the existing `event-logger` lib so external monitors can react.
 *
 * Hook event: WorktreeRemove (async, timeout: 5s).
 */

import type { HookContext, HookInput, HookResult } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import { writeWithRetry } from '../lib/session-registry.js';
import { deleteChild } from '../lib/children-bus.js';
import { appendEventLog } from '../lib/event-logger.js';
import { existsSync, unlinkSync } from 'node:fs';
import { basename, join } from 'node:path';

const HOOK_NAME = 'worktree/exit-finalizer';

export function exitFinalizer(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const worktreePath = input.worktree_path;
  if (!worktreePath) return outputSilentSuccess();

  const projectDir = input.project_dir || process.cwd();
  const nowSec = Math.floor(Date.now() / 1000);

  // Look up the child session row by worktree path, then UPDATE the
  // matching worktree_links row. SQL stays in one transaction.
  const resultPayload = JSON.stringify({
    finished_at: nowSec,
    worktree_path: worktreePath,
  });

  let updated = 0;
  let childSids: string[] = [];
  try {
    updated = writeWithRetry(db => {
      // Snapshot the affected child sids before UPDATE (so we can clean up
      // their advisory files even after the SQL transaction commits).
      childSids = (db
        .prepare(
          `SELECT child_sid FROM worktree_links
           WHERE child_sid IN (
             SELECT sid FROM sessions WHERE worktree_path = ?
           )`,
        )
        .all(worktreePath) as { child_sid: string }[]).map(r => r.child_sid);

      const info = db
        .prepare(
          `UPDATE worktree_links
             SET result_status = 'completed',
                 result_payload = ?
           WHERE child_sid IN (
             SELECT sid FROM sessions WHERE worktree_path = ?
           )
             AND result_status IS NULL`,
        )
        .run(resultPayload, worktreePath);
      return Number(info.changes); // node:sqlite returns changes as number|bigint
    });
  } catch (err) {
    ctx.log(HOOK_NAME, `worktree_links update failed: ${(err as Error).message}`);
  }

  // Best-effort cleanup of the advisory `<parentDir>/.claude/state/children/<sid>.json`
  // entries for the now-departed children.
  for (const sid of childSids) {
    deleteChild(projectDir, sid);
  }

  // Best-effort cleanup of any pending marker that was dropped at
  // WorktreeCreate (mirrors the slug-derived filename used by enter-registrar).
  try {
    const slug = basename(worktreePath);
    const pendingPath = join(projectDir, '.claude', 'state', 'worktree-pending', `${slug}.json`);
    if (existsSync(pendingPath)) unlinkSync(pendingPath);
  } catch (err) {
    ctx.log(HOOK_NAME, `pending marker cleanup failed: ${(err as Error).message}`);
  }

  // Emit a structured event so downstream observers (Phase 3 event-log when it
  // lands; bespoke monitors today) can react.
  try {
    appendEventLog('worktree-events.jsonl', {
      ts: nowSec,
      event: 'worktree_done',
      worktree_path: worktreePath,
      rows_updated: updated,
      child_sids: childSids,
    });
  } catch {
    /* non-critical */
  }

  return outputSilentSuccess();
}
